const db={getMember:async e=>{const{data}=await supabase.from("members").select("*").eq("email",e).single();return data||null},createMember:async m=>{const{data:ex}=await supabase.from("members").select("id").eq("email",m.email).single();if(ex)return false;const{error}=await supabase.from("members").insert({name:m.name,email:m.email,password:m.password});return!error},updateMemberPhoto:async(e,p)=>{await supabase.from("members").update({photo:p}).eq("email",e)},getMemberPhoto:async e=>{const{data}=await supabase.from("members").select("photo").eq("email",e).single();return data?.photo||null},getAllMembers:async()=>{const{data}=await supabase.from("members").select("*").order("created_at",{ascending:false});return data||[]},deleteMember:async e=>{await supabase.from("members").delete().eq("email",e);await supabase.from("guests").delete().eq("member_email",e)},getGuests:async e=>{const{data}=await supabase.from("guests").select("*").eq("member_email",e).order("created_at",{ascending:false});return(data||[]).map(g=>({...g,memberEmail:g.member_email,memberName:g.member_name,guestName:g.guest_name}))},getAllGuests:async()=>{const{data}=await supabase.from("guests").select("*").order("created_at",{ascending:false});return(data||[]).map(g=>({...g,memberEmail:g.member_email,memberName:g.member_name,guestName:g.guest_name}))},createGuest:async g=>{const{error}=await supabase.from("guests").insert({member_email:g.memberEmail,member_name:g.memberName,guest_name:g.guestName,verified:false});return!error},deleteGuest:async id=>{const{data}=await supabase.from("guests").select("verified").eq("id",id).single();if(data&&data.verified)return false;await supabase.from("guests").delete().eq("id",id);return true},markGuestVerified:async id=>{await supabase.from("guests").update({verified:true}).eq("id",id)},getAccessLog:async()=>{const{data}=await supabase.from("access_log").select("*").order("timestamp",{ascending:false});return(data||[]).map(l=>({...l,guestName:l.guest_name,memberName:l.member_name,memberEmail:l.member_email}))},addAccessLog:async entry=>{await supabase.from("access_log").insert({guest_name:entry.guestName,member_name:entry.memberName,member_email:entry.memberEmail})},searchGuestByName:async name=>{const{data}=await supabase.from("guests").select("*").ilike("guest_name",name).eq("verified",false).limit(1);const row=data&&data[0]?data[0]:null;return row?{...row,memberEmail:row.member_email,memberName:row.member_name,guestName:row.guest_name}:null},searchMembersByName:async name=>{const{data}=await supabase.from("members").select("*").ilike("name","%"+name+"%");return(data||[]).filter(x=>!x.email.includes("door")&&!x.email.includes("security"))},changePassword:async(email,oldPw,newPw)=>{const{data}=await supabase.from("members").select("password").eq("email",email).single();if(!data)return{ok:false,msg:"Account not found."};if(data.password!==oldPw)return{ok:false,msg:"Current password is incorrect."};await supabase.from("members").update({password:newPw}).eq("email",email);if(localStorage.getItem("mako_saved_pw")===oldPw&&localStorage.getItem("mako_saved_email")===email){localStorage.setItem("mako_saved_pw",newPw)}return{ok:true,msg:"Password changed successfully."}},getAllowedEmails:async()=>{const{data}=await supabase.from("allowed_emails").select("*").order("added_at",{ascending:false});return(data||[]).map(a=>({...a,addedAt:a.added_at}))},addAllowedEmail:async(email,type)=>{const{data:ex}=await supabase.from("allowed_emails").select("id").eq("email",email.toLowerCase()).single();if(ex)return false;const{error}=await supabase.from("allowed_emails").insert({email:email.toLowerCase(),type});return!error},removeAllowedEmail:async email=>{await supabase.from("allowed_emails").delete().eq("email",email.toLowerCase())},isEmailAllowed:async email=>{const{data}=await supabase.from("allowed_emails").select("*").eq("email",email.toLowerCase()).single();return data||null},getContent:async type=>{const{data}=await supabase.from("content").select("*").eq("type",type).order("created_at",{ascending:false});return(data||[]).map(c=>({...c,createdAt:c.created_at}))},addContent:async(type,item)=>{await supabase.from("content").insert({type,title:item.title,description:item.description,price:item.price,date:item.date,time:item.time})},deleteContent:async(type,id)=>{await supabase.from("content").delete().eq("id",id)},updateContent:async(type,id,updates)=>{await supabase.from("content").update(updates).eq("id",id)},addBooking:async b=>{await supabase.from("bookings").insert({member_email:b.memberEmail,member_name:b.memberName,service_name:b.serviceName,price:b.price})},getBookings:async e=>{const{data}=await supabase.from("bookings").select("*").eq("member_email",e).order("created_at",{ascending:false});return data||[]},addOrder:async o=>{await supabase.from("orders").insert({member_email:o.memberEmail,member_name:o.memberName,item_name:o.itemName,price:o.price})},getOrders:async e=>{const{data}=await supabase.from("orders").select("*").eq("member_email",e).order("created_at",{ascending:false});return data||[]},getAllOrders:async()=>{const{data}=await supabase.from("orders").select("*").order("created_at",{ascending:false});return data||[]},getAllBookings:async()=>{const{data}=await supabase.from("bookings").select("*").order("created_at",{ascending:false});return data||[]},getArchive:async memberEmail=>{let q=supabase.from("archive").select("*").order("archived_at",{ascending:false});if(memberEmail)q=q.eq("member_email",memberEmail);const{data}=await q;return(data||[]).map(a=>({...a,memberEmail:a.member_email,memberName:a.member_name,guestName:a.guest_name,archivedAt:a.archived_at,resetDate:a.reset_date}))},clearExpiredGuests:async()=>{const{data:guests}=await supabase.from("guests").select("*");if(guests&&guests.length>0){const resetDate=new Date().toLocaleDateString("en-GB");await supabase.from("archive").insert(guests.map(g=>({member_email:g.member_email,member_name:g.member_name,guest_name:g.guest_name,verified:g.verified,reset_date:resetDate})));await supabase.from("guests").delete().neq("id",0)}}};

