function ChangePassword({email}){const[open,setOpen]=useState(false);const[current,setCurrent]=useState("");const[newPw,setNewPw]=useState("");const[confirm,setConfirm]=useState("");const[err,setErr]=useState("");const[ok,setOk]=useState("");const submit=async()=>{setErr("");setOk("");if(!current||!newPw||!confirm)return setErr("All fields required.");if(newPw.length<6)return setErr("Min 6 characters.");if(newPw!==confirm)return setErr("Passwords do not match.");const res=await db.changePassword(email,current,newPw);if(!res.ok)return setErr(res.msg);setOk(res.msg);setCurrent("");setNewPw("");setConfirm("");setTimeout(()=>{setOk("");setOpen(false)},2000)};if(!open)return<button onClick={()=>setOpen(true)} style={{width:"100%",background:"#1a1a1a",border:"1px solid #2a2a2a",color:"#fff",borderRadius:10,padding:12,fontSize:13,fontWeight:700,cursor:"pointer",marginBottom:10}}>Change Password</button>;return<div style={{...c.card,marginBottom:10}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}><div style={{fontWeight:700,fontSize:14}}>Change Password</div><button onClick={()=>{setOpen(false);setErr("");setOk("")}} style={{background:"none",border:"none",color:"#777",fontSize:18,cursor:"pointer",padding:0}}>✕</button></div>{err&&<div style={c.err}>{err}</div>}{ok&&<div style={c.ok}>{ok}</div>}<label style={c.label}>Current Password</label><input style={c.input} type="password" placeholder="Current password" value={current} onChange={e=>setCurrent(e.target.value)}/><label style={c.label}>New Password</label><input style={c.input} type="password" placeholder="New password" value={newPw} onChange={e=>setNewPw(e.target.value)}/><label style={c.label}>Confirm New Password</label><input style={c.input} type="password" placeholder="Confirm new password" value={confirm} onChange={e=>setConfirm(e.target.value)} onKeyDown={e=>e.key==="Enter"&&submit()}/><button style={c.btnWhite} onClick={submit}>Update Password →</button></div>}

function TabBar({active,onTab,tabs}){return<div style={{flexShrink:0,background:"#111",borderTop:"1px solid #1e1e1e",display:"flex",height:64,zIndex:100}}>{tabs.map(t=>{const on=active===t.id;return<button key={t.id} onClick={()=>onTab(t.id)} style={{flex:1,background:"none",border:"none",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4,outline:"none",position:"relative"}}>{on&&<div style={{position:"absolute",top:0,left:"50%",transform:"translateX(-50%)",width:28,height:2,background:"#fff",borderRadius:"0 0 2px 2px"}}/>}<div style={{color:on?"#fff":"#555"}}>{t.icon}</div><span style={{fontSize:8,fontWeight:700,letterSpacing:1.2,textTransform:"uppercase",color:on?"#fff":"#555"}}>{t.label}</span></button>})}</div>}

function useClock(){const[time,setTime]=useState(new Date());useEffect(()=>{const t=setInterval(()=>setTime(new Date()),1000);return()=>clearInterval(t)},[]);const pad=n=>String(n).padStart(2,"0");const h=time.getHours(),m=time.getMinutes();return{timeStr:`${h%12||12}:${pad(m)} ${h>=12?"PM":"AM"}`,dateStr:time.toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}).toUpperCase()}}

function useDailyRefresh(){useEffect(()=>{const check=()=>{const now=new Date(),last=localStorage.getItem("mako_last_refresh"),lastDate=last?new Date(last):null;if(now.getHours()>=6&&(!lastDate||lastDate.toDateString()!==now.toDateString())){db.clearExpiredGuests();localStorage.setItem("mako_last_refresh",now.toISOString())}};check();const i=setInterval(check,60000);return()=>clearInterval(i)},[])}

function AuthScreen({onLogin,onAdminTap}){const[mode,setMode]=useState("login");const[form,setForm]=useState(()=>({name:"",email:localStorage.getItem("mako_saved_email")||"",password:localStorage.getItem("mako_saved_pw")||"",confirm:""}));const[remember,setRemember]=useState(()=>!!localStorage.getItem("mako_saved_email"));const[err,setErr]=useState("");const[ok,setOk]=useState("");const[taps,setTaps]=useState(0);const set=k=>e=>setForm(p=>({...p,[k]:e.target.value}));const tap=()=>{const n=taps+1;setTaps(n);if(n>=7){onAdminTap();setTaps(0)}setTimeout(()=>setTaps(0),3000)};const login=async()=>{setErr("");if(!form.email||!form.password)return setErr("Email and password required.");const m=await db.getMember(form.email);if(!m||m.password!==form.password)return setErr("Invalid email or password.");if(remember){localStorage.setItem("mako_saved_email",form.email);localStorage.setItem("mako_saved_pw",form.password)}else{localStorage.removeItem("mako_saved_email");localStorage.removeItem("mako_saved_pw")}onLogin({name:m.name,email:m.email,memberId:m.id})};const signup=async()=>{setErr("");setOk("");if(!form.name||!form.email||!form.password)return setErr("All fields required.");if(form.password!==form.confirm)return setErr("Passwords do not match.");if(form.password.length<6)return setErr("Min 6 characters.");const allowed=await db.isEmailAllowed(form.email);if(!allowed)return setErr("This email has not been approved. Please contact an admin to be added.");const ok2=await db.createMember({name:form.name,email:form.email,password:form.password});if(!ok2)return setErr("Email already registered.");setOk("Account created!");setMode("login");setForm({name:"",email:"",password:"",confirm:""})};return<div style={c.page}><div style={c.authCard}>{mode==="signup"&&<button style={{background:"none",border:"none",color:"#aaa",fontSize:11,cursor:"pointer",padding:0,marginBottom:18}} onClick={()=>{setMode("login");setErr("");setOk("")}}>← Back</button>}<div style={c.logo} onClick={tap}>MAKO</div><div style={c.title}>{mode==="login"?"Welcome back":"Create account"}</div><div style={c.desc}>{mode==="login"?"Sign in to your account.":"Join Mako."}</div>{err&&<div style={c.err}>{err}</div>}{ok&&<div style={c.ok}>{ok}</div>}{mode==="signup"&&<><label style={c.label}>Full Name</label><input style={c.input} placeholder="Your name" value={form.name} onChange={set("name")}/></>}<label style={c.label}>Email</label><input style={c.input} type="email" placeholder="you@example.com" value={form.email} onChange={set("email")} onKeyDown={e=>e.key==="Enter"&&mode==="login"&&login()}/><label style={c.label}>Password</label><input style={c.input} type="password" placeholder="Password" value={form.password} onChange={set("password")} onKeyDown={e=>e.key==="Enter"&&(mode==="login"?login():signup())}/>{mode==="signup"&&<><label style={c.label}>Confirm Password</label><input style={c.input} type="password" placeholder="Confirm" value={form.confirm} onChange={set("confirm")}/></>}<button style={c.btnWhite} onClick={mode==="login"?login:signup}>{mode==="login"?"Sign In":"Create Account"} →</button>{mode==="login"&&<div style={{marginTop:10}}><label style={{display:"flex",alignItems:"center",gap:7,cursor:"pointer"}}><input type="checkbox" checked={remember} onChange={e=>setRemember(e.target.checked)} style={{width:15,height:15,accentColor:"#fff"}}/><span style={{fontSize:11,color:"#aaa"}}>Remember me</span></label></div>}<div style={{marginTop:14,textAlign:"center",fontSize:12,color:"#aaa"}}>{mode==="login"?<span>No account? <button style={c.btnGhost} onClick={()=>{setMode("signup");setErr("");setOk("")}}>Sign up</button></span>:<span>Have an account? <button style={c.btnGhost} onClick={()=>{setMode("login");setErr("");setOk("")}}>Sign in</button></span>}</div></div><div style={{marginTop:20,textAlign:"center",fontSize:9,color:"#555",letterSpacing:1,textTransform:"uppercase"}}>Sponsored by Upsidian Limited</div></div>}

function MemberApp({user,onLogout}){const[tab,setTab]=useState("home");const[photo,setPhoto]=useState(null);const[activeTile,setActiveTile]=useState(null);useDailyRefresh();useEffect(()=>{(async()=>{const p=await db.getMemberPhoto(user.email);if(p)setPhoto(p)})()},[user.email]);const onPhoto=async d=>{setPhoto(d);await db.updateMemberPhoto(user.email,d)};const tabs=[{id:"home",label:"Home",icon:<IHome/>},{id:"list",label:"Guest List",icon:<IList/>},{id:"settings",label:"Settings",icon:<IGear/>}];return<div style={c.appWrap}><div style={c.content}>{tab==="home"&&!activeTile&&<MemberHome user={user} photo={photo} onPhoto={onPhoto} onLogout={onLogout} onTile={setActiveTile}/>}{tab==="home"&&activeTile&&<TileDetail tile={activeTile} user={user} onBack={()=>setActiveTile(null)}/>}{tab==="list"&&<GuestList user={user}/>}{tab==="settings"&&<MemberSettings user={user} photo={photo} onPhoto={onPhoto} onLogout={onLogout}/>}</div><TabBar active={tab} onTab={t=>{setTab(t);setActiveTile(null)}} tabs={tabs}/></div>}

function TileDetail({tile,user,onBack}){const[items,setItems]=useState([]);const[loading,setLoading]=useState(true);const[orderMsg,setOrderMsg]=useState("");useEffect(()=>{(async()=>{setItems(await db.getContent(tile));setLoading(false)})()},[tile]);const placeOrder=async item=>{await db.addOrder({memberEmail:user.email,memberName:user.name,itemName:item.title,price:item.price});setOrderMsg(item.title+" ordered!");setTimeout(()=>setOrderMsg(""),2500)};const bookService=async item=>{await db.addBooking({memberEmail:user.email,memberName:user.name,serviceName:item.title,price:item.price});setOrderMsg(item.title+" booked!");setTimeout(()=>setOrderMsg(""),2500)};const titles={news:"News & Announcements",services:"Services",events:"Upcoming Events",food:"Pre Order Food",connect:"Member Network",contact:"Contact Us"};const descs={news:"Latest from Mako",services:"Book member services",events:"What's coming up",food:"Order ahead for tonight",connect:"Connect with members",contact:"Get in touch with us"};return<div style={{padding:14}}><div style={{paddingTop:14,marginBottom:16,display:"flex",alignItems:"center",gap:10}}><button onClick={onBack} style={{background:"none",border:"none",color:"#fff",fontSize:20,cursor:"pointer",padding:0}}>←</button><div><div style={{fontWeight:800,fontSize:20,color:"#fff"}}>{titles[tile]||tile}</div><div style={{fontSize:11,color:"#aaa",marginTop:2}}>{descs[tile]||""}</div></div></div>{orderMsg&&<div style={c.ok}>{orderMsg}</div>}{loading?<div style={{color:"#777",fontSize:12}}>Loading...</div>:items.length===0?<div style={{textAlign:"center",padding:"32px 16px",background:"#141414",border:"1px solid #1e1e1e",borderRadius:12}}><div style={{fontSize:28,marginBottom:8}}>{tile==="news"?"📰":tile==="food"?"🍽️":tile==="services"?"⚡":tile==="events"?"📅":tile==="contact"?"💬":"👥"}</div><div style={{fontSize:13,color:"#999",fontWeight:600}}>Nothing here yet</div><div style={{fontSize:11,color:"#777",marginTop:4}}>Check back soon for updates.</div></div>:items.map(item=><div key={item.id} style={c.card}><div style={{fontWeight:700,fontSize:14,color:"#fff",marginBottom:4}}>{item.title}</div>{item.description&&<div style={{fontSize:12,color:"#aaa",marginBottom:8,lineHeight:1.5}}>{item.description}</div>}{item.price&&<div style={{fontSize:13,fontWeight:700,color:"#6bff6b",marginBottom:8}}>₦{Number(item.price).toLocaleString()}</div>}{item.date&&<div style={{fontSize:10,color:"#999",marginBottom:6}}>📅 {item.date}</div>}{item.time&&<div style={{fontSize:10,color:"#999",marginBottom:6}}>🕐 {item.time}</div>}{tile==="food"&&<button onClick={()=>placeOrder(item)} style={{width:"100%",background:"#0d1a0d",border:"1px solid #1a3d1a",color:"#6bff6b",borderRadius:8,padding:"9px 0",fontSize:12,fontWeight:700,cursor:"pointer"}}>Order Now</button>}{tile==="services"&&<button onClick={()=>bookService(item)} style={{width:"100%",background:"#0d1a0d",border:"1px solid #1a3d1a",color:"#6bff6b",borderRadius:8,padding:"9px 0",fontSize:12,fontWeight:700,cursor:"pointer"}}>Book</button>}{tile==="events"&&<div style={{fontSize:10,color:"#777",fontStyle:"italic"}}>Open to all members</div>}<div style={{fontSize:9,color:"#555",marginTop:6}}>{new Date(item.createdAt).toLocaleDateString()}</div></div>)}</div>}

function MemberHome({user,photo,onPhoto,onLogout,onTile}){const{timeStr,dateStr}=useClock();const fileRef=useRef();const firstName=user.name.split(" ")[0];const readFile=e=>{const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=ev=>onPhoto(ev.target.result);r.readAsDataURL(f)};const tiles=[{label:"News",icon:<INews/>,desc:"Latest updates",key:"news"},{label:"Services",icon:<IServices/>,desc:"Member services",key:"services"},{label:"Events",icon:<IEvents/>,desc:"Upcoming events",key:"events"},{label:"Pre Order",icon:<IFood/>,desc:"Pre order food",key:"food"},{label:"Connect",icon:<IConnect/>,desc:"Member network",key:"connect"},{label:"Contact Us",icon:<IContact/>,desc:"Get in touch",key:"contact"}];return<div><div style={{background:"linear-gradient(175deg,#0c0c0c 0%,#141414 100%)",padding:"22px 16px 20px",borderBottom:"1px solid #1e1e1e",position:"relative",overflow:"hidden"}}><div style={{position:"absolute",inset:0,backgroundImage:"linear-gradient(#ffffff05 1px,transparent 1px),linear-gradient(90deg,#ffffff05 1px,transparent 1px)",backgroundSize:"36px 36px",pointerEvents:"none"}}/><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",position:"relative",zIndex:1,marginBottom:18}}><div style={{fontSize:9,color:"#ffffff66",letterSpacing:1.5,textTransform:"uppercase"}}>Member Portal</div><div style={{fontWeight:800,fontSize:18,letterSpacing:6,color:"#fff",userSelect:"none"}}>MAKO</div></div><div style={{display:"flex",alignItems:"center",gap:14,marginBottom:20,position:"relative",zIndex:1}}><div style={{position:"relative",flexShrink:0,cursor:"pointer"}} onClick={()=>fileRef.current.click()}><div style={{width:64,height:64,borderRadius:"50%",background:"#1e1e1e",border:"2px solid #ffffff20",overflow:"hidden",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 20px #00000066"}}>{photo?<img src={photo} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>:<span style={{fontSize:26,fontWeight:800,color:"#fff"}}>{user.name.charAt(0).toUpperCase()}</span>}</div><div style={{position:"absolute",bottom:0,right:0,width:22,height:22,borderRadius:"50%",background:"#fff",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 2px 6px #000"}}><ICamera/></div><input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={readFile}/></div><div><div style={{fontSize:24,fontWeight:800,color:"#fff",lineHeight:1,letterSpacing:-0.5}}>Hi, {firstName}!</div></div></div><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",position:"relative",zIndex:1}}><div><div style={{fontSize:26,fontWeight:800,color:"#fff",fontFamily:"monospace",letterSpacing:0.5}}>{timeStr}</div><div style={{fontSize:9,color:"#ffffff66",letterSpacing:2,marginTop:2}}>{dateStr}</div></div><button onClick={onLogout} style={{background:"none",border:"1px solid #ffffff18",color:"#ffffff55",borderRadius:18,padding:"8px 14px",fontSize:10,fontWeight:700,letterSpacing:1.2,cursor:"pointer",textTransform:"uppercase"}}>Sign Out</button></div></div><div style={{padding:"16px 14px 0"}}><div style={{fontSize:9,fontWeight:700,color:"#999",letterSpacing:2,textTransform:"uppercase",marginBottom:12,textAlign:"center"}}>Quick Access</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>{tiles.map(tile=><HomeTile key={tile.label} tile={tile} onTap={()=>onTile(tile.key)}/>)}</div><div style={{marginTop:20,paddingTop:14,borderTop:"1px solid #1a1a1a",textAlign:"center"}}><div style={{fontSize:8,color:"#777",letterSpacing:2,textTransform:"uppercase"}}>Mako · Member Portal</div></div></div></div>}

function HomeTile({tile,onTap}){const[hov,setHov]=useState(false);return<button onClick={onTap} onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)} onTouchStart={()=>setHov(true)} onTouchEnd={()=>setTimeout(()=>setHov(false),180)} style={{background:hov?"#1c1c1c":"#141414",border:"1px solid "+(hov?"#2e2e2e":"#1e1e1e"),borderRadius:14,padding:"20px 10px 16px",cursor:"pointer",textAlign:"center",outline:"none",display:"flex",flexDirection:"column",alignItems:"center",gap:10,transform:hov?"scale(0.97)":"scale(1)",transition:"all 0.14s"}}><div style={{color:hov?"#fff":"#999",transition:"color 0.14s"}}>{tile.icon}</div><div><div style={{fontWeight:800,fontSize:13,color:"#fff"}}>{tile.label}</div><div style={{fontSize:10,color:"#aaa",marginTop:2}}>{tile.desc}</div></div></button>}

function GuestList({user}){const[guests,setGuests]=useState([]);const[archive,setArchive]=useState([]);const[name,setName]=useState("");const[err,setErr]=useState("");const[suc,setSuc]=useState("");const[loading,setLoading]=useState(true);const[showArchive,setShowArchive]=useState(false);const load=async()=>{setGuests(await db.getGuests(user.email));setArchive(await db.getArchive(user.email));setLoading(false)};useEffect(()=>{load()},[user.email]);const add=async()=>{setErr("");setSuc("");if(!name.trim())return setErr("Enter guest name.");if(guests.length>=10)return setErr("Max 10 guests.");await db.createGuest({memberEmail:user.email,memberName:user.name,guestName:name.trim(),verified:false});setGuests(await db.getGuests(user.email));setName("");setSuc("Guest added!");setTimeout(()=>setSuc(""),2000)};const del=async id=>{const g=guests.find(x=>x.id===id);if(g&&g.verified){setErr("Cannot remove checked-in guests.");setTimeout(()=>setErr(""),3000);return}await db.deleteGuest(id);setGuests(await db.getGuests(user.email))};const archiveByDate=archive.reduce((acc,g)=>{const key=g.resetDate||new Date(g.archivedAt).toLocaleDateString("en-GB");if(!acc[key])acc[key]=[];acc[key].push(g);return acc},{});const archiveDates=Object.keys(archiveByDate).sort((a,b)=>new Date(b)-new Date(a));if(showArchive)return<div style={{padding:14}}><div style={{paddingTop:14,marginBottom:16,display:"flex",alignItems:"center",gap:10}}><button onClick={()=>setShowArchive(false)} style={{background:"none",border:"none",color:"#fff",fontSize:20,cursor:"pointer",padding:0}}>←</button><div><div style={{fontWeight:800,fontSize:20,color:"#fff"}}>Archive</div><div style={{fontSize:11,color:"#aaa",marginTop:2}}>Past guest invites</div></div></div>{archiveDates.length===0?<div style={{textAlign:"center",padding:"32px 16px"}}><div style={{fontSize:28,marginBottom:10}}>📂</div><div style={{fontSize:13,color:"#999",fontWeight:600}}>No archived guests yet</div></div>:archiveDates.map(date=><div key={date} style={{marginBottom:20}}><div style={{fontSize:9,fontWeight:700,color:"#aaa",letterSpacing:2,textTransform:"uppercase",marginBottom:8,paddingBottom:7,borderBottom:"1px solid #1a1a1a"}}>{date}</div>{archiveByDate[date].map(g=><div key={g.id} style={{...c.card,opacity:0.8}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><div><div style={{fontWeight:600,fontSize:13,color:"#ccc"}}>{g.guestName}</div></div><span style={{background:g.verified?"#0a1a0a":"#1a1a1a",border:g.verified?"1px solid #1a3d1a":"1px solid #2a2a2a",color:g.verified?"#4dcc4d":"#555",borderRadius:20,padding:"3px 9px",fontSize:9,fontWeight:700}}>{g.verified?"✓ Attended":"Not used"}</span></div></div>)}</div>)}</div>;return<div style={{padding:14}}><div style={{paddingTop:14,marginBottom:14,display:"flex",alignItems:"flex-start",justifyContent:"space-between"}}><div><div style={{fontWeight:800,fontSize:20,color:"#fff"}}>My Guest List</div><div style={{fontSize:11,color:"#aaa",marginTop:2}}>Add and manage your guests</div></div><button onClick={()=>setShowArchive(true)} style={{background:"#1a1a1a",border:"1px solid #2a2a2a",color:"#bbb",borderRadius:8,padding:"6px 10px",fontSize:10,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",gap:4,marginTop:3}}>Archive {archive.length>0&&<span style={{background:"#2a2a2a",borderRadius:10,padding:"1px 5px",fontSize:9}}>{archive.length}</span>}</button></div><div style={c.card}><div style={{fontWeight:700,fontSize:14,marginBottom:10}}>Add a Guest</div>{err&&<div style={c.err}>{err}</div>}{suc&&<div style={c.ok}>{suc}</div>}<label style={c.label}>Guest Full Name</label><input style={c.input} placeholder="e.g. John Smith" value={name} onChange={e=>setName(e.target.value)} onKeyDown={e=>e.key==="Enter"&&add()}/><div style={{fontSize:10,color:"#aaa",marginBottom:12}}>{guests.length}/10 guests added.</div><button style={c.btnWhite} onClick={add}>Add Guest →</button><div style={{fontSize:9,color:"#999",marginTop:10,lineHeight:1.5}}>ℹ️ Lists reset daily at 6am.</div></div><div style={c.section}>Tonight's Guests ({guests.length})</div>{loading?<div style={{color:"#777",fontSize:12}}>Loading...</div>:guests.length===0?<div style={{textAlign:"center",padding:"24px 16px",background:"#141414",border:"1px solid #1e1e1e",borderRadius:12}}><div style={{fontSize:24,marginBottom:6}}>👤</div><div style={{fontSize:12,color:"#999",fontWeight:600}}>No guests yet</div></div>:guests.map(g=><div key={g.id} style={c.card}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:7}}><strong style={{fontSize:13,color:"#e0e0e0"}}>{g.guestName}</strong><span style={{background:g.verified?"#0a1e0a":"#1a1a1a",border:g.verified?"1px solid #1a3d1a":"1px solid #2a2a2a",color:g.verified?"#6bff6b":"#777",borderRadius:20,padding:"3px 9px",fontSize:9,fontWeight:700}}>{g.verified?"✓ In":"Pending"}</span></div><button onClick={()=>del(g.id)} disabled={g.verified} style={{width:"100%",background:"#1a0a0a",border:g.verified?"1px solid #2a2a2a":"1px solid #3d1515",color:g.verified?"#555":"#ff6b6b",borderRadius:8,padding:"7px 0",fontSize:11,cursor:g.verified?"not-allowed":"pointer",fontWeight:600,opacity:g.verified?0.5:1}}>{g.verified?"Checked In":"Remove"}</button></div>)}</div>}

function MemberSettings({user,photo,onPhoto,onLogout}){const fileRef=useRef();const readFile=e=>{const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=ev=>onPhoto(ev.target.result);r.readAsDataURL(f)};return<div style={{padding:14}}><div style={{paddingTop:14,marginBottom:16}}><div style={{fontWeight:800,fontSize:20,color:"#fff"}}>Settings</div></div><div style={{...c.card,marginBottom:16}}><div style={{display:"flex",alignItems:"center",gap:12}}><div style={{position:"relative",cursor:"pointer"}} onClick={()=>fileRef.current.click()}><div style={{width:50,height:50,borderRadius:"50%",background:"#1a1a1a",border:"1px solid #2a2a2a",overflow:"hidden",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,fontWeight:700,color:"#fff"}}>{photo?<img src={photo} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/>:user.name.charAt(0).toUpperCase()}</div><div style={{position:"absolute",bottom:0,right:0,width:18,height:18,borderRadius:"50%",background:"#fff",display:"flex",alignItems:"center",justifyContent:"center"}}><ICamera/></div><input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={readFile}/></div><div><div style={{fontWeight:700,fontSize:14,color:"#fff"}}>{user.name}</div><div style={{fontSize:11,color:"#aaa",marginTop:2}}>{user.email}</div></div></div></div><div style={{...c.section,marginBottom:10}}>Info</div><div style={{...c.card,marginBottom:16}}>{[["Guest limit","10 per session"],["Daily reset","6:00 AM"],["Version","1.0.0"]].map(([k,v],i,a)=><div key={k} style={{display:"flex",justifyContent:"space-between",padding:"9px 0",borderBottom:i<a.length-1?"1px solid #1a1a1a":"none"}}><span style={{fontSize:12,color:"#aaa"}}>{k}</span><span style={{fontSize:12,color:"#fff"}}>{v}</span></div>)}</div><div style={{...c.section,marginBottom:10}}>Account</div><ChangePassword email={user.email}/><button onClick={onLogout} style={{width:"100%",background:"#1a0a0a",border:"1px solid #3d1515",color:"#ff6b6b",borderRadius:10,padding:12,fontSize:13,fontWeight:700,cursor:"pointer"}}>Sign Out</button></div>}

function DoorApp({user,onLogout}){const[tab,setTab]=useState("home");const[searchName,setSearchName]=useState("");const[result,setResult]=useState(null);const[log,setLog]=useState([]);const[allGuests,setAllGuests]=useState([]);const[loading,setLoading]=useState(false);const[showRecents,setShowRecents]=useState(true);const[memberQuery,setMemberQuery]=useState("");const[memberResults,setMemberResults]=useState([]);const[selectedMember,setSelectedMember]=useState(null);const[memberGuests,setMemberGuests]=useState([]);const[logMemberFilter,setLogMemberFilter]=useState("");const[logTimeFilter,setLogTimeFilter]=useState("all");const{timeStr,dateStr}=useClock();useDailyRefresh();const loadData=async()=>{setLog(await db.getAccessLog());setAllGuests(await db.getAllGuests())};useEffect(()=>{loadData()},[]);const verify=async()=>{if(!searchName.trim())return;setLoading(true);setResult(null);const guest=await db.searchGuestByName(searchName.trim());if(!guest){setResult({type:"not_found"})}else{await db.markGuestVerified(guest.id);await db.addAccessLog({guestName:guest.guestName,memberName:guest.memberName,memberEmail:guest.memberEmail});await loadData();setResult({type:"granted",guest})}setSearchName("");setLoading(false)};const verifyFromList=async guest=>{if(guest.verified)return;await db.markGuestVerified(guest.id);await db.addAccessLog({guestName:guest.guestName,memberName:guest.memberName,memberEmail:guest.memberEmail});await loadData();if(selectedMember)setMemberGuests(await db.getGuests(selectedMember.email));setResult({type:"granted",guest})};const searchMembers=async()=>{if(!memberQuery.trim()){setMemberResults([]);return}setMemberResults(await db.searchMembersByName(memberQuery.trim()))};const selectMember=async member=>{setSelectedMember(member);setMemberGuests(await db.getGuests(member.email));setMemberQuery("");setMemberResults([])};const getFilteredLog=()=>{let filtered=[...log];if(logMemberFilter.trim()){const q=logMemberFilter.toLowerCase();filtered=filtered.filter(l=>l.memberName?.toLowerCase().includes(q)||l.guestName?.toLowerCase().includes(q))}if(logTimeFilter!=="all"){const now=Date.now();if(logTimeFilter==="today"){const ts=new Date();ts.setHours(0,0,0,0);filtered=filtered.filter(l=>new Date(l.timestamp)>=ts)}else{const ms={"1h":3600000,"3h":10800000};filtered=filtered.filter(l=>now-new Date(l.timestamp).getTime()<ms[logTimeFilter])}}return filtered};const filteredLog=getFilteredLog();const tabs=[{id:"home",label:"Home",icon:<IHome/>},{id:"members",label:"Members",icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>},{id:"list",label:"Log",icon:<IList/>},{id:"settings",label:"Settings",icon:<IGear/>}];return<div style={c.appWrap}><div style={c.header}><div><div style={c.hLogo}>MAKO</div><div style={c.hSub}>Door Verification</div></div><div style={{textAlign:"right"}}><div style={{fontSize:12,fontWeight:700,fontFamily:"monospace"}}>{timeStr}</div><div style={{fontSize:8,color:"#aaa",marginTop:1}}>{dateStr}</div></div></div><div style={c.content}>{tab==="home"&&<div style={{padding:14}}><div style={{background:"#141414",border:"1px solid #1e1e1e",borderRadius:14,padding:16,marginBottom:14}}><div style={{fontWeight:700,fontSize:15,marginBottom:3}}>Verify Guest</div><div style={{color:"#aaa",fontSize:12,marginBottom:14}}>Enter the guest's full name to check in.</div><div style={{display:"flex",gap:7}}><input value={searchName} onChange={e=>setSearchName(e.target.value)} onKeyDown={e=>e.key==="Enter"&&verify()} placeholder="Guest full name" style={{...c.input,flex:1,marginBottom:0}}/><button style={{background:"#fff",color:"#000",border:"none",padding:"11px 14px",borderRadius:10,fontWeight:700,cursor:"pointer",fontSize:13,flexShrink:0}} onClick={verify} disabled={loading}>{loading?"...":"Verify"}</button></div>{result&&result.type==="granted"&&<div style={{marginTop:12,padding:14,borderRadius:10,background:"#0d1a0d",border:"1px solid #1a3d1a"}}><div style={{color:"#6bff6b",fontWeight:700,fontSize:14,marginBottom:8}}>✓ Access Granted</div>{[["Guest",result.guest.guestName],["Invited by",result.guest.memberName]].map(([k,v])=><div key={k} style={{fontSize:12,color:"#ccc",marginBottom:3}}><span style={{color:"#aaa",display:"inline-block",minWidth:72}}>{k}</span>{v}</div>)}</div>}{result&&result.type==="not_found"&&<div style={{marginTop:12,padding:14,borderRadius:10,background:"#1a0d0d",border:"1px solid #3d1a1a"}}><div style={{color:"#ff6b6b",fontWeight:700,fontSize:14,marginBottom:5}}>✗ Not Found</div><div style={{fontSize:12,color:"#aa6666"}}>No pending guest. Try the Members tab.</div></div>}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:14}}>{[{label:"Checked In",value:allGuests.filter(g=>g.verified).length,color:"#6bff6b"},{label:"Pending",value:allGuests.filter(g=>!g.verified).length,color:"#c8860a"},{label:"Total",value:allGuests.length,color:"#fff"}].map(s=><div key={s.label} style={{background:"#141414",border:"1px solid #1e1e1e",borderRadius:10,padding:"10px 6px",textAlign:"center"}}><div style={{fontSize:20,fontWeight:800,color:s.color}}>{s.value}</div><div style={{fontSize:8,color:"#aaa",marginTop:2,textTransform:"uppercase",letterSpacing:1}}>{s.label}</div></div>)}</div><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}><div style={{...c.section,marginBottom:0}}>Recent ({log.length})</div><button onClick={()=>setShowRecents(!showRecents)} style={{background:"#1a1a1a",border:"1px solid #2a2a2a",borderRadius:20,padding:"4px 12px",fontSize:10,fontWeight:600,cursor:"pointer",color:showRecents?"#fff":"#777",display:"flex",alignItems:"center",gap:6}}><div style={{width:28,height:16,borderRadius:8,background:showRecents?"#6bff6b":"#333",position:"relative",transition:"background 0.2s"}}><div style={{width:12,height:12,borderRadius:"50%",background:"#fff",position:"absolute",top:2,left:showRecents?14:2,transition:"left 0.2s"}}/></div>{showRecents?"Visible":"Hidden"}</button></div>{showRecents&&(log.length===0?<div style={{color:"#777",fontSize:12,padding:"16px 0",textAlign:"center"}}>No check-ins yet today.</div>:log.slice(0,8).map(l=><div key={l.id} style={{background:"#141414",border:"1px solid #1e1e1e",borderRadius:10,padding:10,marginBottom:7,fontSize:12}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:2}}><strong style={{color:"#e0e0e0"}}>{l.guestName}</strong><span style={{color:"#6bff6b",fontSize:10}}>✓ In</span></div><div style={{display:"flex",justifyContent:"space-between"}}><span style={{color:"#999"}}>by {l.memberName}</span>{l.timestamp&&<span style={{color:"#777",fontSize:10}}>{new Date(l.timestamp).toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit"})}</span>}</div></div>))}</div>}{tab==="members"&&<div style={{padding:14}}>{selectedMember?<div><button onClick={()=>{setSelectedMember(null);setMemberGuests([]);setResult(null)}} style={{background:"none",border:"none",color:"#fff",fontSize:18,cursor:"pointer",padding:0,marginBottom:14}}>← Back</button><div style={{...c.card,marginBottom:14}}><div style={{display:"flex",alignItems:"center",gap:12}}><div style={{width:44,height:44,borderRadius:"50%",background:"#1e1e1e",border:"1px solid #2a2a2a",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,fontWeight:700,color:"#fff"}}>{selectedMember.name.charAt(0).toUpperCase()}</div><div><div style={{fontWeight:700,fontSize:15,color:"#fff"}}>{selectedMember.name}</div><div style={{fontSize:11,color:"#aaa",marginTop:2}}>{selectedMember.email}</div></div></div></div>{result&&result.type==="granted"&&<div style={{marginBottom:12,padding:14,borderRadius:10,background:"#0d1a0d",border:"1px solid #1a3d1a"}}><div style={{color:"#6bff6b",fontWeight:700,fontSize:13}}>✓ {result.guest.guestName} checked in</div></div>}<div style={c.section}>Guest List ({memberGuests.length})</div>{memberGuests.length===0?<div style={{textAlign:"center",padding:"24px 16px",background:"#141414",border:"1px solid #1e1e1e",borderRadius:12}}><div style={{fontSize:24,marginBottom:6}}>👤</div><div style={{fontSize:12,color:"#999",fontWeight:600}}>No guests on this member's list</div></div>:memberGuests.map(g=><div key={g.id} style={c.card}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><div><div style={{fontWeight:600,fontSize:13,color:"#e0e0e0"}}>{g.guestName}</div><div style={{fontSize:10,color:g.verified?"#6bff6b":"#c8860a",marginTop:3}}>{g.verified?"✓ Already checked in":"⏳ Pending"}</div></div>{!g.verified?<button onClick={()=>verifyFromList(g)} style={{background:"#0d1a0d",border:"1px solid #1a3d1a",color:"#6bff6b",borderRadius:8,padding:"7px 14px",fontSize:11,fontWeight:700,cursor:"pointer"}}>Check In</button>:<span style={{background:"#0a1e0a",border:"1px solid #1a3d1a",color:"#6bff6b",borderRadius:20,padding:"3px 10px",fontSize:10,fontWeight:700}}>✓ In</span>}</div></div>)}</div>:<div><div style={{fontWeight:800,fontSize:18,color:"#fff",marginBottom:3}}>Member Lookup</div><div style={{fontSize:12,color:"#aaa",marginBottom:14}}>Search by member name to view their guest list.</div><div style={{display:"flex",gap:7,marginBottom:14}}><input value={memberQuery} onChange={e=>setMemberQuery(e.target.value)} onKeyDown={e=>e.key==="Enter"&&searchMembers()} placeholder="Member name..." style={{...c.input,flex:1,marginBottom:0}}/><button style={{background:"#fff",color:"#000",border:"none",padding:"11px 14px",borderRadius:10,fontWeight:700,cursor:"pointer",fontSize:13,flexShrink:0}} onClick={searchMembers}>Search</button></div>{memberResults.length>0&&<div><div style={c.section}>Results ({memberResults.length})</div>{memberResults.map(m=><button key={m.id} onClick={()=>selectMember(m)} style={{...c.card,width:"100%",cursor:"pointer",textAlign:"left",display:"flex",alignItems:"center",gap:12}}><div style={{width:38,height:38,borderRadius:"50%",background:"#1e1e1e",border:"1px solid #2a2a2a",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,fontWeight:700,color:"#fff",flexShrink:0}}>{m.name.charAt(0).toUpperCase()}</div><div><div style={{fontWeight:600,fontSize:13,color:"#e0e0e0"}}>{m.name}</div><div style={{fontSize:10,color:"#999",marginTop:2}}>{m.email}</div></div><div style={{marginLeft:"auto",color:"#777",fontSize:18}}>→</div></button>)}</div>}{memberQuery&&memberResults.length===0&&<div style={{textAlign:"center",padding:"20px 16px",color:"#777",fontSize:12}}>No members found</div>}</div>}</div>}{tab==="list"&&<div style={{padding:14}}><div style={{fontWeight:800,fontSize:18,color:"#fff",marginBottom:12}}>Access Log</div><input style={{...c.input,marginBottom:10}} type="text" placeholder="Filter by guest or member name..." value={logMemberFilter} onChange={e=>setLogMemberFilter(e.target.value)}/><div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>{[{id:"all",label:"All Time"},{id:"1h",label:"Last Hour"},{id:"3h",label:"Last 3 Hrs"},{id:"today",label:"Today"}].map(f=><button key={f.id} onClick={()=>setLogTimeFilter(f.id)} style={{background:logTimeFilter===f.id?"#fff":"#1a1a1a",color:logTimeFilter===f.id?"#000":"#aaa",border:"1px solid "+(logTimeFilter===f.id?"#fff":"#2a2a2a"),borderRadius:20,padding:"5px 12px",fontSize:10,fontWeight:700,cursor:"pointer",letterSpacing:0.5}}>{f.label}</button>)}</div><div style={c.section}>Showing {filteredLog.length} of {log.length}</div>{filteredLog.length===0?<div style={{color:"#777",fontSize:12,textAlign:"center",padding:"20px 0"}}>No entries match your filters.</div>:filteredLog.map(l=><div key={l.id} style={{background:"#141414",border:"1px solid #1e1e1e",borderRadius:10,padding:10,marginBottom:7,fontSize:12}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:2}}><strong style={{color:"#e0e0e0"}}>{l.guestName}</strong><span style={{color:"#6bff6b",fontSize:10}}>✓ In</span></div><div style={{display:"flex",justifyContent:"space-between"}}><span style={{color:"#999"}}>by {l.memberName}</span>{l.timestamp&&<span style={{color:"#777",fontSize:10}}>{new Date(l.timestamp).toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit"})}</span>}</div></div>)}</div>}{tab==="settings"&&<div style={{padding:14}}><div style={{...c.card,marginBottom:16}}><div style={{display:"flex",alignItems:"center",gap:12}}><div style={{width:44,height:44,borderRadius:"50%",background:"#1a1a1a",border:"1px solid #2a2a2a",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,fontWeight:700,color:"#fff"}}>{user.name.charAt(0).toUpperCase()}</div><div><div style={{fontWeight:700,fontSize:14,color:"#fff"}}>{user.name}</div><div style={{fontSize:11,color:"#aaa",marginTop:2}}>{user.email}</div><div style={{fontSize:9,color:"#777",marginTop:2,letterSpacing:0.5,textTransform:"uppercase"}}>Security / Door</div></div></div></div><div style={{...c.section,marginBottom:10}}>Tonight's Summary</div><div style={{...c.card,marginBottom:16}}>{[["Total Guests",allGuests.length],["Checked In",allGuests.filter(g=>g.verified).length],["Pending",allGuests.filter(g=>!g.verified).length],["Log Entries",log.length]].map(([k,v],i,a)=><div key={k} style={{display:"flex",justifyContent:"space-between",padding:"9px 0",borderBottom:i<a.length-1?"1px solid #1a1a1a":"none"}}><span style={{fontSize:12,color:"#aaa"}}>{k}</span><span style={{fontSize:12,fontWeight:700,color:"#fff"}}>{v}</span></div>)}</div><div style={{...c.section,marginBottom:10}}>Account</div><ChangePassword email={user.email}/><button onClick={onLogout} style={{width:"100%",background:"#1a0a0a",border:"1px solid #3d1515",color:"#ff6b6b",borderRadius:10,padding:12,fontSize:13,fontWeight:700,cursor:"pointer"}}>Sign Out</button></div>}</div><TabBar active={tab} onTab={setTab} tabs={tabs}/></div>}

function AdminPanel({onExit}){const ADMIN_PW="Test123456789";const[authed,setAuthed]=useState(false);const[pw,setPw]=useState("");const[pwErr,setPwErr]=useState("");const[tab,setTab]=useState("home");const[members,setMembers]=useState([]);const[security,setSecurity]=useState([]);const[guests,setGuests]=useState([]);const[log,setLog]=useState([]);const[allowed,setAllowed]=useState([]);const[sq,setSq]=useState("");const[userView,setUserView]=useState("members");const[addEmail,setAddEmail]=useState("");const[addErr,setAddErr]=useState("");const[addOk,setAddOk]=useState("");const[deleteTarget,setDeleteTarget]=useState(null);const[contentTab,setContentTab]=useState("news");const[contentItems,setContentItems]=useState([]);const[showAddContent,setShowAddContent]=useState(false);const[cf,setCf]=useState({title:"",description:"",price:"",date:"",time:""});const[cfErr,setCfErr]=useState("");const[cfOk,setCfOk]=useState("");const loadContent=async type=>{setContentItems(await db.getContent(type||contentTab))};const load=async()=>{const all=await db.getAllMembers();setMembers(all.filter(x=>!x.email.includes("door")&&!x.email.includes("security")));setSecurity(all.filter(x=>x.email.includes("door")||x.email.includes("security")));setGuests(await db.getAllGuests());setLog(await db.getAccessLog());setAllowed(await db.getAllowedEmails());await loadContent()};useEffect(()=>{if(authed)load()},[authed]);const tryLogin=()=>{if(pw===ADMIN_PW){setAuthed(true);setPwErr("")}else setPwErr("Incorrect password.")};const addUser=async type=>{setAddErr("");setAddOk("");const email=addEmail.trim().toLowerCase();if(!email)return setAddErr("Email is required.");if(!email.includes("@"))return setAddErr("Enter a valid email.");if(type==="security"&&!email.includes("door")&&!email.includes("security"))return setAddErr("Security emails must contain 'door' or 'security'.");if(type==="member"&&(email.includes("door")||email.includes("security")))return setAddErr("Member emails should not contain 'door' or 'security'.");const ok=await db.addAllowedEmail(email,type);if(!ok)return setAddErr("Email already on the approved list.");setAddOk((type==="member"?"Member":"Security")+" email added!");setAddEmail("");await load();setTimeout(()=>setAddOk(""),2000)};const confirmDelete=async()=>{if(!deleteTarget)return;await db.deleteMember(deleteTarget.email);await db.removeAllowedEmail(deleteTarget.email);setDeleteTarget(null);await load()};if(!authed)return<div style={c.page}><div style={c.authCard}><div style={c.logo}>MAKO</div><div style={{fontSize:9,color:"#bbb",letterSpacing:1.5,marginBottom:24}}>ADMIN PANEL</div><div style={{fontSize:15,fontWeight:700,marginBottom:16}}>Admin Access</div>{pwErr&&<div style={c.err}>{pwErr}</div>}<label style={c.label}>Admin Password</label><input style={c.input} type="password" placeholder="Password" value={pw} onChange={e=>setPw(e.target.value)} onKeyDown={e=>e.key==="Enter"&&tryLogin()}/><button style={{...c.btnWhite,marginTop:2}} onClick={tryLogin}>Enter Admin Panel →</button><div style={{marginTop:14,textAlign:"center"}}><button onClick={onExit} style={{background:"none",border:"none",color:"#999",fontSize:11,cursor:"pointer"}}>← Back to App</button></div></div></div>;const adminTabs=[{id:"home",label:"Home",icon:<IHome/>},{id:"users",label:"Users",icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>},{id:"settings",label:"Settings",icon:<IGear/>}];const btnRed={background:"#1a0a0a",color:"#ff6b6b",border:"1px solid #3d1515",padding:"4px 9px",borderRadius:6,fontSize:10,cursor:"pointer"};const currentList=userView==="members"?members:security;const filteredUsers=currentList.filter(u=>u.name.toLowerCase().includes(sq.toLowerCase())||u.email.toLowerCase().includes(sq.toLowerCase()));const pendingAllowed=allowed.filter(a=>{const isRegistered=[...members,...security].some(m=>m.email.toLowerCase()===a.email.toLowerCase());if(userView==="members")return a.type==="member"&&!isRegistered;return a.type==="security"&&!isRegistered});return<div style={c.appWrap}><div style={c.header}><div><div style={c.hLogo}>MAKO</div><div style={c.hSub}>Admin Panel</div></div><div style={{display:"flex",gap:6}}><button style={{background:"#1a1a1a",border:"1px solid #2a2a2a",color:"#aaa",borderRadius:8,padding:"5px 10px",fontSize:10,cursor:"pointer"}} onClick={load}>Refresh</button><button style={{background:"#1a1a1a",border:"1px solid #2a2a2a",color:"#aaa",borderRadius:8,padding:"5px 10px",fontSize:10,cursor:"pointer"}} onClick={onExit}>Exit</button></div></div><div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:6,padding:"8px 14px",background:"#0d0d0d",borderBottom:"1px solid #1a1a1a",flexShrink:0}}>{[{label:"Members",value:members.length},{label:"Security",value:security.length},{label:"Guests",value:guests.length},{label:"Check-ins",value:log.length}].map(s=><div key={s.label} style={{background:"#141414",border:"1px solid #1e1e1e",borderRadius:9,padding:"8px 4px",textAlign:"center"}}><div style={{fontSize:18,fontWeight:800}}>{s.value}</div><div style={{fontSize:8,color:"#aaa",marginTop:1}}>{s.label}</div></div>)}</div>{deleteTarget&&<div style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.75)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}><div style={{background:"#1a1a1a",border:"1px solid #2a2a2a",borderRadius:16,padding:24,width:"100%",maxWidth:320}}><div style={{fontSize:16,fontWeight:700,color:"#fff",marginBottom:8}}>Confirm Delete</div><div style={{fontSize:13,color:"#aaa",marginBottom:6}}>Are you sure you want to delete this {deleteTarget.type}?</div><div style={{...c.card,marginBottom:16}}><div style={{fontWeight:600,fontSize:13,color:"#e0e0e0"}}>{deleteTarget.name||deleteTarget.email}</div><div style={{fontSize:11,color:"#999",marginTop:3}}>{deleteTarget.email}</div></div><div style={{fontSize:11,color:"#aa6666",marginBottom:16,lineHeight:1.5}}>This will remove their account, guest list, and approved email. This action cannot be undone.</div><div style={{display:"flex",gap:8}}><button onClick={()=>setDeleteTarget(null)} style={{flex:1,background:"#1a1a1a",border:"1px solid #2a2a2a",color:"#aaa",borderRadius:10,padding:12,fontSize:13,fontWeight:700,cursor:"pointer"}}>Cancel</button><button onClick={confirmDelete} style={{flex:1,background:"#3d1515",border:"1px solid #5a2020",color:"#ff6b6b",borderRadius:10,padding:12,fontSize:13,fontWeight:700,cursor:"pointer"}}>Delete</button></div></div></div>}<div style={c.content}>{tab==="home"&&<div style={{padding:14}}><div style={{fontWeight:800,fontSize:18,color:"#fff",marginBottom:3}}>Manage Content</div><div style={{fontSize:11,color:"#aaa",marginBottom:14}}>Update what members see in their portal.</div><div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>{[{id:"news",label:"News",emoji:"📰"},{id:"food",label:"Food Menu",emoji:"🍽️"},{id:"services",label:"Services",emoji:"⚡"},{id:"events",label:"Events",emoji:"📅"},{id:"contact",label:"Contact",emoji:"💬"}].map(ct=><button key={ct.id} onClick={async()=>{setContentTab(ct.id);setShowAddContent(false);setCfErr("");setCfOk("");await loadContent(ct.id)}} style={{background:contentTab===ct.id?"#fff":"#1a1a1a",color:contentTab===ct.id?"#000":"#aaa",border:"1px solid "+(contentTab===ct.id?"#fff":"#2a2a2a"),borderRadius:20,padding:"5px 10px",fontSize:10,fontWeight:700,cursor:"pointer"}}>{ct.emoji} {ct.label}</button>)}</div>{!showAddContent?<button onClick={()=>{setShowAddContent(true);setCf({title:"",description:"",price:"",date:"",time:""});setCfErr("");setCfOk("")}} style={{width:"100%",background:"#1a1a1a",border:"1px solid #2a2a2a",color:"#fff",borderRadius:10,padding:12,fontSize:13,fontWeight:700,cursor:"pointer",marginBottom:14}}>+ Add {contentTab==="news"?"Announcement":contentTab==="food"?"Menu Item":contentTab==="services"?"Service":contentTab==="events"?"Event":"Info"}</button>:<div style={{...c.card,marginBottom:14}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}><div style={{fontWeight:700,fontSize:14}}>Add {contentTab==="news"?"Announcement":contentTab==="food"?"Menu Item":contentTab==="services"?"Service":contentTab==="events"?"Event":"Info"}</div><button onClick={()=>setShowAddContent(false)} style={{background:"none",border:"none",color:"#777",fontSize:18,cursor:"pointer"}}>✕</button></div>{cfErr&&<div style={c.err}>{cfErr}</div>}{cfOk&&<div style={c.ok}>{cfOk}</div>}<label style={c.label}>Title</label><input style={c.input} placeholder={contentTab==="news"?"Announcement title":contentTab==="food"?"e.g. Jollof Rice":contentTab==="services"?"e.g. Boat Ride to Koko":contentTab==="events"?"Event name":"Title"} value={cf.title} onChange={e=>setCf({...cf,title:e.target.value})}/><label style={c.label}>Description</label><textarea style={{...c.input,minHeight:60,resize:"vertical"}} placeholder="Details..." value={cf.description} onChange={e=>setCf({...cf,description:e.target.value})}/>{(contentTab==="food"||contentTab==="services")&&<><label style={c.label}>Price (₦)</label><input style={c.input} type="number" placeholder="e.g. 5000" value={cf.price} onChange={e=>setCf({...cf,price:e.target.value})}/></>}{contentTab==="events"&&<><label style={c.label}>Date</label><input style={c.input} placeholder="e.g. April 5, 2026" value={cf.date} onChange={e=>setCf({...cf,date:e.target.value})}/><label style={c.label}>Time</label><input style={c.input} placeholder="e.g. 8:00 PM" value={cf.time} onChange={e=>setCf({...cf,time:e.target.value})}/></>}<button style={c.btnWhite} onClick={async()=>{setCfErr("");setCfOk("");if(!cf.title.trim())return setCfErr("Title is required.");await db.addContent(contentTab,{title:cf.title.trim(),description:cf.description.trim(),price:cf.price||null,date:cf.date||null,time:cf.time||null});setCfOk("Added!");setCf({title:"",description:"",price:"",date:"",time:""});await loadContent(contentTab);setTimeout(()=>{setCfOk("");setShowAddContent(false)},1500)}}>Add →</button></div>}<div style={c.section}>{contentTab==="news"?"Announcements":contentTab==="food"?"Menu Items":contentTab==="services"?"Services":contentTab==="events"?"Events":"Info"} ({contentItems.length})</div>{contentItems.length===0?<div style={{color:"#777",fontSize:12,textAlign:"center",padding:"16px 0"}}>No {contentTab} items yet. Add one above.</div>:contentItems.map(item=><div key={item.id} style={c.card}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}><div style={{flex:1}}><div style={{fontWeight:600,color:"#e0e0e0",fontSize:13}}>{item.title}</div>{item.description&&<div style={{fontSize:11,color:"#999",marginTop:3,lineHeight:1.4}}>{item.description.length>80?item.description.substring(0,80)+"...":item.description}</div>}{item.price&&<div style={{fontSize:12,fontWeight:700,color:"#6bff6b",marginTop:3}}>₦{Number(item.price).toLocaleString()}</div>}{item.date&&<div style={{fontSize:10,color:"#999",marginTop:2}}>{item.date}{item.time?" · "+item.time:""}</div>}</div><button style={btnRed} onClick={async()=>{await db.deleteContent(contentTab,item.id);await loadContent(contentTab)}}>Delete</button></div></div>)}</div>}{tab==="users"&&<div style={{padding:14}}><div style={{display:"flex",background:"#1a1a1a",borderRadius:10,padding:3,marginBottom:14,border:"1px solid #2a2a2a"}}>{[{id:"members",label:"Members"},{id:"security",label:"Security"}].map(v=><button key={v.id} onClick={()=>{setUserView(v.id);setSq("")}} style={{flex:1,background:userView===v.id?"#fff":"transparent",color:userView===v.id?"#000":"#777",border:"none",borderRadius:8,padding:"9px 0",fontSize:12,fontWeight:700,cursor:"pointer",transition:"all 0.15s"}}>{v.label}</button>)}</div><div style={{...c.card,marginBottom:14}}><div style={{fontWeight:700,fontSize:14,marginBottom:3}}>Add {userView==="members"?"Member":"Security"}</div><div style={{fontSize:11,color:"#aaa",marginBottom:10}}>{userView==="members"?"Add a member's email to allow them to sign up.":"Add a security email (must contain 'door' or 'security')."}</div>{addErr&&<div style={c.err}>{addErr}</div>}{addOk&&<div style={c.ok}>{addOk}</div>}<div style={{display:"flex",gap:7}}><input value={addEmail} onChange={e=>setAddEmail(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addUser(userView==="members"?"member":"security")} placeholder="email@example.com" style={{...c.input,flex:1,marginBottom:0}}/><button style={{background:"#fff",color:"#000",border:"none",padding:"11px 14px",borderRadius:10,fontWeight:700,cursor:"pointer",fontSize:12,flexShrink:0}} onClick={()=>addUser(userView==="members"?"member":"security")}>Add</button></div></div><input style={{...c.input,marginBottom:10}} type="text" placeholder={"Search "+userView+"..."} value={sq} onChange={e=>setSq(e.target.value)}/><div style={c.section}>{userView==="members"?"Members":"Security"} ({filteredUsers.length})</div>{filteredUsers.length===0?<div style={{color:"#777",fontSize:12,marginBottom:14}}>None found.</div>:filteredUsers.map(u=><div key={u.id} style={c.card}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><div><div style={{fontWeight:600,color:"#e0e0e0",fontSize:12}}>{u.name}</div><div style={{fontSize:10,color:"#999",marginTop:2}}>{u.email}</div>{userView==="members"&&<div style={{fontSize:10,color:"#aaa",marginTop:1}}>{guests.filter(g=>g.memberEmail===u.email).length} guests</div>}<div style={{fontSize:9,color:"#6bff6b",marginTop:2}}>✓ Registered</div></div><button style={btnRed} onClick={()=>setDeleteTarget({email:u.email,name:u.name,type:userView==="members"?"member":"security staff"})}>Delete</button></div></div>)}{pendingAllowed.length>0&&<><div style={{...c.section,marginTop:16}}>Pending Sign-Up ({pendingAllowed.length})</div>{pendingAllowed.map(a=><div key={a.email} style={c.card}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><div><div style={{fontWeight:600,color:"#e0e0e0",fontSize:12}}>{a.email}</div><div style={{fontSize:9,color:"#c8860a",marginTop:3}}>⏳ Awaiting sign-up</div></div><button style={btnRed} onClick={()=>setDeleteTarget({email:a.email,name:a.email,type:"approved email"})}>Remove</button></div></div>)}</>}</div>}{tab==="settings"&&<div style={{padding:14}}><div style={{...c.section,marginBottom:10}}>Summary</div><div style={{...c.card,marginBottom:16}}>{[["Members",members.length],["Security",security.length],["Approved Emails",allowed.length],["Guests",guests.length],["Verified",guests.filter(g=>g.verified).length],["Check-ins",log.length]].map(([k,v],i,a)=><div key={k} style={{display:"flex",justifyContent:"space-between",padding:"9px 0",borderBottom:i<a.length-1?"1px solid #1a1a1a":"none"}}><span style={{fontSize:12,color:"#aaa"}}>{k}</span><span style={{fontSize:12,fontWeight:700,color:"#fff"}}>{v}</span></div>)}<div style={{fontSize:10,color:"#999",marginTop:10}}>Resets daily at 6am. All guests archived on reset.</div></div><button onClick={onExit} style={{width:"100%",background:"#1a0a0a",border:"1px solid #3d1515",color:"#ff6b6b",borderRadius:10,padding:12,fontSize:13,fontWeight:700,cursor:"pointer"}}>Exit Admin Panel</button></div>}</div><TabBar active={tab} onTab={setTab} tabs={adminTabs}/></div>}

export default function App(){const[user,setUser]=useState(null);const[role,setRole]=useState(null);const[admin,setAdmin]=useState(false);const logout=()=>{setUser(null);setRole(null)};const handleLogin=m=>{setUser(m);setRole(m.email.includes("door")||m.email.includes("security")?"door":"member")};const content=(()=>{if(admin)return<AdminPanel onExit={()=>setAdmin(false)}/>;if(!user)return<AuthScreen onLogin={handleLogin} onAdminTap={()=>setAdmin(true)}/>;if(role==="door")return<DoorApp user={user} onLogout={logout}/>;return<MemberApp user={user} onLogout={logout}/>})();return<MobileShell>{content}</MobileShell>}
